class Solution:
    def maxProduct(self, root):
        MOD = 10**9 + 7
        subs = []
        def total(node):
            if not node:
                return 0
            s = node.val + total(node.left) + total(node.right)
            subs.append(s)
            return s
        t = total(root)
        best = max(s * (t - s) for s in subs)
        return best % MOD

